import svg.path
from svg.path import Path, Line, CubicBezier

def svg_to_gcode(svg_path, scale=1.0):
    path = Path(svg_path)
    gcode = ["G21", "G90", "G0 X0 Y0"]
    for segment in path:
        if isinstance(segment, Line):
            x, y = segment.end.real * scale, segment.end.imag * scale
            gcode.append(f"G1 X{x:.3f} Y{y:.3f}")
    return "\n".join(gcode)
